using UnityEngine;

/// <summary>
/// Gestor do Diário — Sistema de Pistas/Rumores, no mesmo padrão singleton de
/// GameVariables/PlayerProgress/MissionManager (auto-criado antes da primeira
/// cena).
///
/// Não guarda estado próprio: lê/escreve as listas de IDs em
/// PlayerProgress (obtainedClueIds/heardRumorIds/foundRumorIds — persistidas no
/// save). Os dados de exibição (imagem/título/descrição) vivem nos
/// ScriptableObjects (MissionData.clues / RumorData), nunca aqui.
///
/// Usado por Action_ShowFullscreenImage (guardar pista), Action_AddRumor,
/// Action_MarkRumorFound e pelas condições Condition_HasClue/
/// Condition_HeardRumor/Condition_RumorFound. DiarySectionUI subscreve os
/// eventos abaixo para repopular a lista de Pistas/Rumores quando algo muda
/// enquanto o Menu de Pausa está aberto (normalmente não acontece, mas é seguro).
/// </summary>
public class JournalManager : MonoBehaviour
{
    public static JournalManager Instance { get; private set; }

    /// <summary>
    /// Marca instâncias criadas automaticamente por <see cref="EnsureExists"/>
    /// antes da primeira cena carregar (ver PlayerProgress.cs para a explicação
    /// completa — Tarefa #15 "GameBootstrap e singletons").
    /// </summary>
    private bool isAutoFallback;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(JournalManager) + " (Fallback)");
        var instance = go.AddComponent<JournalManager>();
        instance.isAutoFallback = true;
    }

    /// <summary>Disparado quando uma pista de missão é obtida pela primeira vez (Action_ShowFullscreenImage com "saveAsClue").</summary>
    public static event System.Action<MissionData, string> OnClueObtained;

    /// <summary>Disparado quando um rumor é ouvido pela primeira vez (Action_AddRumor).</summary>
    public static event System.Action<RumorData> OnRumorHeard;

    /// <summary>Disparado quando um rumor é marcado como "encontrado" pela primeira vez (Action_MarkRumorFound).</summary>
    public static event System.Action<RumorData> OnRumorFound;

    // ---------------- Pistas de Missão ----------------

    /// <summary>True se a pista "clueId" da missão indicada já foi obtida.</summary>
    public bool HasClue(MissionData mission, string clueId)
    {
        return PlayerProgress.Instance != null && PlayerProgress.Instance.HasClue(mission, clueId);
    }

    /// <summary>Regista "clueId" da missão indicada como obtido (idempotente) e dispara <see cref="OnClueObtained"/> na primeira vez.</summary>
    public void GiveClue(MissionData mission, string clueId)
    {
        if (mission == null || string.IsNullOrEmpty(clueId) || PlayerProgress.Instance == null) return;

        bool wasObtained = PlayerProgress.Instance.HasClue(mission, clueId);
        PlayerProgress.Instance.MarkClueObtained(mission, clueId);

        if (!wasObtained) OnClueObtained?.Invoke(mission, clueId);
    }

    // ---------------- Rumores ----------------

    /// <summary>True se este rumor já foi ouvido (aparece na secção "Rumores" do Diário).</summary>
    public bool HasHeardRumor(RumorData rumor)
    {
        return rumor != null && PlayerProgress.Instance != null && PlayerProgress.Instance.HasHeardRumor(rumor.rumorId);
    }

    /// <summary>Regista o rumor como ouvido (idempotente) e dispara <see cref="OnRumorHeard"/> na primeira vez.</summary>
    public void AddRumor(RumorData rumor)
    {
        if (rumor == null || string.IsNullOrEmpty(rumor.rumorId) || PlayerProgress.Instance == null) return;

        bool wasHeard = PlayerProgress.Instance.HasHeardRumor(rumor.rumorId);
        PlayerProgress.Instance.MarkRumorHeard(rumor.rumorId);

        if (!wasHeard) OnRumorHeard?.Invoke(rumor);
    }

    /// <summary>True se este rumor já foi marcado como "encontrado" (ícone de "Check").</summary>
    public bool IsRumorFound(RumorData rumor)
    {
        return rumor != null && PlayerProgress.Instance != null && PlayerProgress.Instance.IsRumorFound(rumor.rumorId);
    }

    /// <summary>Marca o rumor como "encontrado" (idempotente) e dispara <see cref="OnRumorFound"/> na primeira vez. Não remove o rumor da lista de "Rumores" — apenas mostra o "Check".</summary>
    public void MarkRumorFound(RumorData rumor)
    {
        if (rumor == null || string.IsNullOrEmpty(rumor.rumorId) || PlayerProgress.Instance == null) return;

        bool wasFound = PlayerProgress.Instance.IsRumorFound(rumor.rumorId);
        PlayerProgress.Instance.MarkRumorFound(rumor.rumorId);

        if (!wasFound) OnRumorFound?.Invoke(rumor);
    }
}
